  ('pukao-c5fb3965-moex-00294', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '住家鄰近軍事機場之人民，因戰機夜間起降噪音過大，影響個人健康，擬請求行政法院判命戰機不得於夜 間起降。人民應提起何種行政訴訟類型？', '["撤銷訴訟", "課予義務訴訟", "違法確認訴訟", "一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00295', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於行政訴訟之管轄，下列敘述何者正確？', '["因不動產之物權或法律關係涉訟者，專屬不動產所在地之行政法院管轄", "因行政契約涉訟者，如經當事人定有債務履行地，得由該履行地之法院管轄", "因公法上之保險事件涉訟者，於投保單位為原告時，得由其主事務所所在地之行政法院管轄", "關於公務員職務關係之訴訟，得由公務員住居所地之行政法院管轄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00296', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '有關行政訴訟之都市計畫審查程序，下列敘述何者正確？', '["都市計畫審查程序以審查法規性質之都市計畫為限", "不服都市計畫之變更，應先提起訴願，未獲救濟始得提起都市計畫審查訴訟", "為維護公共利益，人民得依都市計畫審查程序請求變更都市計畫", "都市計畫發布機關收受起訴狀後，應在2個月內重新自我審查是否合法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00297', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '下列何者不得請求行政上之損失補償？', '["既成道路之徵收", "捷運施工時造成民房龜裂之情形", "授予利益之合法行政處分，為除去對於公益之危害，而由原處分機關依職權廢止者", "土地徵收致土地上之違章建築改良物須拆除"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00298', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '關於國家賠償法，下列敘述何者正確？', '["國家賠償法施行前公務員違法行為所生之損害，不適用國家賠償法", "公務員違法執行職務之行為，造成外國人產生損害時，不適用我國國家賠償法", "公務員違法執行職務之行為，造成民營公司損害時，應優先適用民法", "公務員違法執行職務之行為，對人民產生損害，無其他求償規定時，始適用國家賠償法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
  ('pukao-c5fb3965-moex-00299', 'pukao-c5fb3965', 'pukao-c5fb3965-moex-112-d1a761c9', 'sub-pukao-c5fb3965-02', NULL, 'single_choice', '在經適當警告或標示的開放山域、水域，人民從事冒險或具危險性活動時，因公共設施設置或管理有欠缺 而權利受損害，依據國家賠償法，下列何者為國家得減輕賠償責任之事由？', '["主管機關未獲求援呼救致未及時援助", "人民須事前向主管機關申請許可", "人民受損害之地點須在自然公物內之設施", "人民所受之損害須非財產上之權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:39+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "戶政"}'::jsonb, NULL),
